mapper.select:
SELECT i.id, i.inquiry_no AS inquiryNo, i.customer_id AS customerId, cust.company_name AS customerName, i.contact_id AS contactId, cont.full_name AS contactName, cont.email AS contactEmail, i.source, CASE i.source WHEN 'alibaba' THEN '阿里巴巴国际站' WHEN 'website' THEN '官网' WHEN 'email' THEN '邮件' WHEN 'exhibition' THEN '展会' WHEN 'referral' THEN '推荐' ELSE i.source END AS sourceDesc, i.priority, CASE i.priority WHEN 'HIGH' THEN '高优先级' WHEN 'MEDIUM' THEN '中优先级' WHEN 'LOW' THEN '低优先级' ELSE i.priority END AS priorityDesc, i.status, CASE i.status WHEN 'NEW' THEN '新询盘' WHEN 'PROCESSING' THEN '处理中' WHEN 'QUOTED' THEN '已报价' WHEN 'CONVERTED' THEN '已转化' WHEN 'CLOSED' THEN '已关闭' ELSE i.status END AS statusDesc, i.product_interest AS productInterest, i.quantity, i.target_price AS targetPrice, i.currency, i.deadline AS expectedDeliveryDate, i.assigned_to AS ownerId, u.nickname AS ownerName, u.dept_id AS departmentId, d.dept_name AS departmentName, i.created_time AS createdTime, i.updated_time AS updatedTime, i.closed_time AS closedTime, i.remark FROM crm_inquiry i LEFT JOIN crm_customer cust ON i.customer_id = cust.id AND cust.deleted = 0 LEFT JOIN crm_contact cont ON i.contact_id = cont.id AND cont.deleted = 0 LEFT JOIN sys_user u ON i.assigned_to = u.id LEFT JOIN sys_dept d ON u.dept_id = d.id AND d.deleted = 0 WHERE i.deleted = 0
AND i.inquiry_no LIKE CONCAT('%', #{query.inquiryNo}, '%')
AND cust.company_name LIKE CONCAT('%', #{query.customerName}, '%')
AND cont.full_name LIKE CONCAT('%', #{query.contactName}, '%')
AND i.source = #{query.source}
AND i.priority = #{query.priority}
AND i.status = #{query.status}
AND i.assigned_to = #{query.ownerId}
AND u.dept_id = #{query.departmentId}
AND i.created_time >= #{query.startTime}
AND i.created_time <= #{query.endTime}
AND i.status = 'CONVERTED'
AND i.status != 'CONVERTED'
ORDER BY i.created_time DESC

SELECT i.id, i.inquiry_no AS inquiryNo, cust.company_name AS customerName, cont.full_name AS contactName, cont.email AS contactEmail, CASE i.source WHEN 'alibaba' THEN '阿里巴巴国际站' WHEN 'website' THEN '官网' WHEN 'email' THEN '邮件' WHEN 'exhibition' THEN '展会' WHEN 'referral' THEN '推荐' ELSE i.source END AS sourceDesc, CASE i.priority WHEN 'HIGH' THEN '高优先级' WHEN 'MEDIUM' THEN '中优先级' WHEN 'LOW' THEN '低优先级' ELSE i.priority END AS priorityDesc, i.product_interest AS productInterest, i.quantity, i.target_price AS targetPrice, i.currency, i.deadline AS expectedDeliveryDate, u.nickname AS ownerName, d.dept_name AS departmentName, i.created_time AS createdTime, i.remark FROM crm_inquiry i LEFT JOIN crm_customer cust ON i.customer_id = cust.id AND cust.deleted = 0 LEFT JOIN crm_contact cont ON i.contact_id = cont.id AND cont.deleted = 0 LEFT JOIN sys_user u ON i.assigned_to = u.id LEFT JOIN sys_dept d ON u.dept_id = d.id AND d.deleted = 0 WHERE i.deleted = 0
AND i.inquiry_no LIKE CONCAT('%', #{query.inquiryNo}, '%')
AND cust.company_name LIKE CONCAT('%', #{query.customerName}, '%')
AND i.source = #{query.source}
AND i.status = #{query.status}
ORDER BY i.created_time DESC
